SELECT AVG(renewal_count) AS average_renewals
FROM borrowing_records
WHERE status = 'Overdue';

SELECT COUNT(*) AS returned_records_count
FROM borrowing_records
WHERE status = 'Returned';

SELECT book_id
FROM borrowing_records
WHERE status = 'Overdue';

SELECT book_id, MAX(renewal_count) AS max_renewal_count
FROM borrowing_records
GROUP BY book_id;

SELECT user_name, membership_date
FROM library_users
ORDER BY membership_date DESC;

SELECT user_name, email
FROM library_users
WHERE strftime('%Y', membership_date) = '2020';
